insert into public.lessons (module_id, lesson_number, title, estimated_time, lesson_overview, learning_objectives, lesson_notes, worked_example, common_mistakes, real_world_tip, exercise, reflection_question, knowledge_check, completion_checklist)
select m.id, 2, 'Building the Framework', '14 minute read',
  $$This lesson guides you through assembling the framework using everything from the course.$$,
  array['Assemble the framework','Apply course patterns','Wire up CI'],
  $$## Build steps
- Set up the project (TypeScript, structure)
- Write BDD features and step definitions for key journeys
- Build page objects and components
- Add fixtures, utilities and test data
- Include at least one API test and API-driven setup
- Add a GitHub Actions workflow with report upload

## Quality bar
Robust locators, web-first assertions, independent data, green CI.$$,
  $$Following the course patterns, you build login and checkout features with page objects, seed data via the API, and wire GitHub Actions so the suite runs green on every push.$$,
  $$- Skipping CI or leaving it red
- Brittle locators and hard waits creeping back in
- Tests that depend on order or shared data$$,
  $$Apply the standards you learned, not shortcuts. This project is what an employer will actually open — let it show your best, most professional work.$$,
  $$Build your framework to the quality bar: robust locators, web-first assertions, independent data, and green CI.$$,
  $$Which qualities define a strong portfolio framework?$$,
  $$Your portfolio framework should have: A) brittle locators but many tests B) robust locators, independent data and green CI C) no CI. (Answer: B)$$,
  array['I can assemble the framework','I wire up CI']
from public.modules m join public.courses c on c.id = m.course_id
where c.slug = 'practical-test-automation-playwright' and m.module_number = 12
on conflict (module_id, lesson_number) do nothing;

insert into public.lessons (module_id, lesson_number, title, estimated_time, lesson_overview, learning_objectives, lesson_notes, worked_example, common_mistakes, real_world_tip, exercise, reflection_question, knowledge_check, completion_checklist)
select m.id, 3, 'Documentation & README', '11 minute read',
  $$A great framework needs a great README. This lesson covers documenting your project so reviewers understand it fast.$$,
  array['Write a clear README','Explain your test strategy','Make the repo easy to run'],
  $$## README checklist
- One-paragraph overview of the project and app under test
- How to install and run the tests
- What is covered and why (your strategy)
- Tech used (Playwright, TypeScript, CI)
- A note on what it demonstrates about you

## Why
Reviewers decide quickly; a clear README frames your work well.$$,
  $$Your README opens with what the framework tests and how to run it in two commands, so a reviewer can clone, run and understand it in minutes.$$,
  $$- No README, so the work has no context
- Instructions that do not actually work
- Walls of text with no structure$$,
  $$The README is the first thing an employer reads. A clear, well-structured one signals professionalism before they see a single line of test code.$$,
  $$Write a README for your project covering overview, how to run, coverage and tech used.$$,
  $$Why is the README so important for a portfolio repo?$$,
  $$A portfolio README should let a reviewer: A) guess how to run it B) clone, run and understand the project quickly C) read only code. (Answer: B)$$,
  array['I can write a clear README','I can explain my test strategy']
from public.modules m join public.courses c on c.id = m.course_id
where c.slug = 'practical-test-automation-playwright' and m.module_number = 12
on conflict (module_id, lesson_number) do nothing;

insert into public.lessons (module_id, lesson_number, title, estimated_time, lesson_overview, learning_objectives, lesson_notes, worked_example, common_mistakes, real_world_tip, exercise, reflection_question, knowledge_check, completion_checklist)
select m.id, 4, 'Publishing & Self-Review', '12 minute read',
  $$The final step is publishing your framework and reviewing it against the model solution. This lesson covers finishing strong.$$,
  array['Publish the project','Self-review against the model','Prepare to present it'],
  $$## Finishing checklist
- Repo is public and CI is green
- README is clear; links work
- Tests are reliable (pass on repeat runs)
- Locators robust; data independent

## Self-review and present
Compare against the model solution, note gaps, and prepare a 60-second walkthrough of what it demonstrates. Submit your repository URL.$$,
  $$You make the repo public, confirm CI is green, run the suite twice to check reliability, then record a 60-second walkthrough explaining your design choices — and submit the URL.$$,
  $$- A private repo or red CI a reviewer cannot use
- Broken links or a stale README
- No ability to talk through your own choices$$,
  $$Be ready to walk through any part of your framework in 60 seconds. Employers value engineers who can explain their design decisions, not just produce code.$$,
  $$Publish your framework, self-review it against the model solution, and submit your GitHub repository URL for review.$$,
  $$What is the final deliverable for this course?$$,
  $$Your capstone submission is: A) a screenshot B) a public GitHub repository URL with a green, documented framework C) a single test file. (Answer: B)$$,
  array['I can publish the project','I can present it confidently']
from public.modules m join public.courses c on c.id = m.course_id
where c.slug = 'practical-test-automation-playwright' and m.module_number = 12
on conflict (module_id, lesson_number) do nothing;

-- ████████████████████████████████████████████████████████████
-- ▶ assignment-templates.sql
-- ████████████████████████████████████████████████████████████

-- ============================================================
-- Assignment templates + assignments for AI and QA-Interview courses.
--
-- 1. Adds assignments.template_slug — references a Resource Vault doc
--    (public/resources/<courseSlug>/<slug>) shown as a downloadable
--    "assignment template" on the module's submission card.
-- 2. Links each existing 90-Day assignment to its matching template.
-- 3. Seeds one practical assignment per module for "AI for QA Testers"
--    and "QA Interview Accelerator" (these had none).
--
-- Idempotent: safe to run more than once.
-- NOTE: the Playwright course has no modules seeded yet, so it gets no
-- assignments here — seed its modules first, then add assignments.
-- ============================================================

alter table public.assignments add column if not exists template_slug text;

-- ---------- 1. 90-Day: link existing assignments to a template ----------
update public.assignments set template_slug = 'sdlc-cheat-sheet'                 where module_id = 'b1000001-0000-0000-0000-000000000001';
update public.assignments set template_slug = 'test-case-template'              where module_id = 'b1000002-0000-0000-0000-000000000001';
update public.assignments set template_slug = 'bug-report-template'             where module_id = 'b1000003-0000-0000-0000-000000000001';
update public.assignments set template_slug = 'agile-testing-cheat-sheet'       where module_id = 'b1000004-0000-0000-0000-000000000001';
update public.assignments set template_slug = 'test-plan-template'              where module_id = 'b1000005-0000-0000-0000-000000000001';
update public.assignments set template_slug = 'test-scenario-template'          where module_id = 'b1000006-0000-0000-0000-000000000001';
update public.assignments set template_slug = 'requirements-traceability-matrix' where module_id = 'b1000007-0000-0000-0000-000000000001';
update public.assignments set template_slug = 'test-strategy-template'          where module_id = 'b1000008-0000-0000-0000-000000000001';
update public.assignments set template_slug = 'test-case-template'              where module_id = 'b1000009-0000-0000-0000-000000000001';
update public.assignments set template_slug = 'final-portfolio-project-workbook' where module_id = 'b1000010-0000-0000-0000-000000000001';
update public.assignments set template_slug = 'qa-career-roadmap-poster'        where module_id = 'b1000011-0000-0000-0000-000000000001';
update public.assignments set template_slug = 'final-portfolio-project-workbook' where module_id = 'b1000012-0000-0000-0000-000000000001';

-- ---------- 2. AI for QA Testers: one assignment per module ----------
insert into public.assignments (module_id, title, instructions, required, submission_type, template_slug)
select m.id, v.title, v.instructions, true, 'file', v.template_slug
from public.modules m
join public.courses c on c.id = m.course_id
cross join (values
  (1,  'Module 1 Assignment — The AI Shift in QA', 'Write a one-page reflection on where AI can and cannot help in testing. List five testing tasks AI can assist with and three decisions that must stay with a human tester, with a short reason for each. Submit as a PDF or DOCX.', 'ai-usage-policy-template'),
  (2,  'Module 2 Assignment — AI Fundamentals for Testers', 'Run three of your own prompts through an AI tool and document, for each: the prompt, the output, and whether you spotted any hallucination or limitation. Conclude with two rules you will follow for responsible AI use. Submit as a PDF or DOCX.', 'ai-prompt-cheat-sheet'),
  (3,  'Module 3 Assignment — Prompt Engineering for QA', 'Using the Prompt Writing Framework, write five well-structured QA prompts (role + context + task + format + constraints) for different testing tasks. Show a before/after for one weak prompt you improved. Submit as a PDF or DOCX.', 'prompt-writing-framework'),
  (4,  'Module 4 Assignment — Requirements Analysis with AI', 'Take a real or sample user story and use AI to find ambiguity, gaps and untestable criteria. Produce five sharp questions you would raise in refinement and mark the two most important. Submit as a PDF or DOCX.', 'ai-requirement-review-workbook'),
  (5,  'Module 5 Assignment — AI-Assisted Test Case Design', 'Generate test cases for a feature using AI, then review them against the AI Test Case Review Checklist. Document at least two issues you found and fixed (e.g. a hallucinated rule, a missing boundary case). Submit as a PDF or DOCX.', 'ai-test-case-review-checklist'),
  (6,  'Module 6 Assignment — Exploratory Testing with AI', 'Use AI to generate 10 exploratory charters for a feature you can access, run two short sessions, and record findings plus three follow-up charters the exploration revealed. Submit as a PDF or DOCX.', 'ai-exploratory-testing-workbook'),
  (7,  'Module 7 Assignment — Defect Reporting with AI', 'Write a bug report yourself, then use AI to review it for clarity and completeness. Submit the before and after versions and list three improvements you accepted and one suggestion you rejected because it was wrong. Submit as a PDF or DOCX.', 'ai-bug-report-review-guide'),
  (8,  'Module 8 Assignment — API Testing with AI', 'Pick a public API and use AI to help you understand its endpoints and generate test ideas. Produce 8 API test ideas (with method, purpose and expected result) and note which AI suggestions you had to correct. Submit as a PDF or DOCX.', 'ai-prompt-library'),
  (9,  'Module 9 Assignment — Automation Support with AI', 'Use AI to support an automation task: generate test data, draft a selector strategy, or explain an error. Document what you asked, what AI produced, and what you verified or changed before trusting it. Submit as a PDF or DOCX.', 'ai-prompt-library'),
  (10, 'Module 10 Assignment — AI in Agile QA Workflows', 'Describe how you would use AI across one sprint (refinement, planning, regression scope, release). For a recent change, use AI to brainstorm impacted areas and produce a prioritised regression set with a one-line scope justification. Submit as a PDF or DOCX.', 'ai-regression-planning-template'),
  (11, 'Module 11 Assignment — AI Risks, Ethics & Governance', 'Write your personal responsible-AI statement (data, verification, accountability) and apply the AI Risk Assessment Checklist to a real task. If any item fails, explain how you would rework the task to pass. Submit as a PDF or DOCX.', 'ai-ethics-governance-guide'),
  (12, 'Module 12 Assignment — Building Your AI QA Workflow', 'Create your personal AI testing toolkit: at least three saved prompts that work for you, your go-to tool per task, and your four personal usage rules. This is your capstone for the course. Submit as a PDF or DOCX.', 'personal-ai-toolkit-planner')
) as v(module_number, title, instructions, template_slug)
where c.slug = 'ai-for-qa-testers'
  and m.module_number = v.module_number
  and not exists (select 1 from public.assignments a where a.module_id = m.id);

-- ---------- 3. QA Interview Accelerator: one assignment per module ----------
insert into public.assignments (module_id, title, instructions, required, submission_type, template_slug)
select m.id, v.title, v.instructions, true, 'file', v.template_slug
from public.modules m
join public.courses c on c.id = m.course_id
cross join (values
  (1, 'Module 1 Assignment — Understanding the QA Interview Process', 'Map a typical QA interview process (stages from application to offer) and, for each stage, note what is assessed and how you will prepare. Use the Interview Day Checklist to build your own pre-interview checklist. Submit as a PDF or DOCX.', 'interview-day-checklist'),
  (2, 'Module 2 Assignment — Your QA Career Story', 'Write your "Tell me about yourself" pitch using the Present–Past–Future formula (60–90 seconds) and record yourself delivering it. Submit the written pitch plus three sentences on what you improved after listening back. Submit as a PDF or DOCX.', 'elevator-pitch-template'),
  (3, 'Module 3 Assignment — Core Software Testing Questions', 'Answer 10 core testing questions from the Question Bank in your own words (e.g. severity vs priority, when to stop testing, test design techniques). Keep each answer tight and add a real example where you can. Submit as a PDF or DOCX.', 'qa-interview-question-bank'),
  (4, 'Module 4 Assignment — Agile, Scrum and Team-Based Questions', 'Prepare answers to five Agile/team questions (e.g. how testing fits in Agile, three amigos, smoke vs regression) and one short STAR story about working in a team. Submit as a PDF or DOCX.', 'technical-qa-interview-cheat-sheet'),
  (5, 'Module 5 Assignment — Scenario-Based QA Questions', 'Prepare STAR answers for four behavioural/scenario questions (a defect you are proud of, a conflict with a developer, working under pressure, a mistake you learned from). Submit as a PDF or DOCX.', 'behavioural-interview-prep-workbook'),
  (6, 'Module 6 Assignment — Test Task Preparation', 'Complete a practice test task: given a simple feature, produce test cases (happy path, negative, boundary) and a short bug report. Then run a mock interview from the practice pack and note your score and one area to improve. Submit as a PDF or DOCX.', 'mock-interview-practice-pack'),
  (7, 'Module 7 Assignment — CV, LinkedIn and Job Applications', 'Update your QA CV using the template and rewrite your LinkedIn headline and About opener. Submit your CV, the LinkedIn text, and a list of 10 target roles you are applying for. Submit as a PDF or DOCX.', 'qa-cv-template'),
  (8, 'Module 8 Assignment — Final Interview Readiness Pack', 'Submit your graduation pack: five STAR answers, your elevator pitch, a 30-60-90 day plan for a target role, and a record of five job applications. This is your final readiness submission. Submit as a PDF or DOCX.', '30-60-90-day-plan-template')
) as v(module_number, title, instructions, template_slug)
where c.slug = 'qa-interview-accelerator'
  and m.module_number = v.module_number
  and not exists (select 1 from public.assignments a where a.module_id = m.id);

-- ████████████████████████████████████████████████████████████
-- ▶ assignment-templates-playwright.sql
-- ████████████████████████████████████████████████████████████

-- ============================================================
-- Assignments for "Practical Test Automation with Playwright".
-- One practical assignment per module, each linked to a matching
-- Automation Resource Vault template (assignments.template_slug).
-- Run AFTER seed-playwright-modules.sql and assignment-templates.sql
-- (which adds the template_slug column). Idempotent.
-- ============================================================

insert into public.assignments (module_id, title, instructions, required, submission_type, template_slug)
select m.id, v.title, v.instructions, true, v.submission_type, v.template_slug
from public.modules m
join public.courses c on c.id = m.course_id
cross join (values
  (1,  'Module 1 Assignment — Automation Fundamentals', 'Review twenty sample test cases (your own or from an app you know) and decide for each whether it should be automated and at which layer (unit, API, UI), with a one-line reason. Summarise your automation strategy in a short document. Submit as a PDF or DOCX.', 'file', 'automation-best-practices-checklist'),
  (2,  'Module 2 Assignment — Behaviour Driven Development', 'Write feature files for Login, Checkout and Registration. Include happy-path, negative and at least one scenario outline with an examples table. Keep the language declarative and readable. Submit as a PDF or DOCX (or a link to the .feature files).', 'file', 'test-structure-naming-guide'),
  (3,  'Module 3 Assignment — Step Definitions', 'Convert your feature files from Module 2 into working step definitions. Keep steps thin and reusable, delegate to page objects, and avoid duplication. Submit your step definition code as a PDF/DOCX export or a repository link.', 'file', 'automation-code-review-checklist'),
  (4,  'Module 4 Assignment — Playwright Essentials', 'Build your first Playwright suite: at least five tests using robust locators (getByRole/getByLabel) and web-first assertions, with no waitForTimeout. Include a screenshot of a passing run and your config. Submit as a PDF/DOCX or a repository link.', 'file', 'locator-strategy-cheat-sheet'),
  (5,  'Module 5 Assignment — Page Object Model', 'Create page objects for Login, Dashboard, Shopping Basket and Checkout, and refactor your tests to use them. Show how a test reads using the page objects. Submit as a PDF/DOCX or a repository link.', 'file', 'page-object-model-template'),
  (6,  'Module 6 Assignment — Test Data Management', 'Create reusable test data for your suite: a factory that generates unique valid records, plus one JSON or CSV data set driving a parameterised test. Show that a test creates and cleans up its own data. Submit as a PDF/DOCX or a repository link.', 'file', 'test-data-management-template'),
  (7,  'Module 7 Assignment — Framework Architecture', 'Refactor your framework into a clean, scalable structure (tests, pages, components, fixtures, utils, data). Document the folder structure and explain two architecture decisions you made. Submit as a PDF/DOCX or a repository link.', 'file', 'test-structure-naming-guide'),
  (8,  'Module 8 Assignment — API Automation', 'Automate a public REST API: write at least five API tests covering GET/POST and an error case, asserting status and key response fields. Then use an API call to set up state for one UI test. Submit as a PDF/DOCX or a repository link.', 'file', 'api-testing-with-playwright-template'),
  (9,  'Module 9 Assignment — Git & CI/CD', 'Connect your framework to GitHub and add a GitHub Actions workflow that installs browsers, runs the suite, and uploads the report. Submit a link to a successful (green) workflow run, plus a short note on your setup.', 'url', 'ci-cd-integration-guide'),
  (10, 'Module 10 Assignment — AI Assisted Automation', 'Use AI to improve your framework: generate or refactor a test/page object, document the prompts you used, what AI produced, and what you verified or changed before trusting it. Include your responsible-AI rules. Submit as a PDF or DOCX.', 'file', 'ai-prompt-library-automation'),
  (11, 'Module 11 Assignment — Framework Maintenance', 'Take an intentionally poor or flaky test (yours or provided) and fix it: diagnose with the checklist and trace, remove sleeps/brittleness, and prove reliability with a repeat-each run. Document before/after. Submit as a PDF or DOCX.', 'file', 'flaky-test-troubleshooting-checklist'),
  (12, 'Module 12 Assignment — Portfolio Project', 'Build a complete automation framework (BDD, feature files, step definitions, Playwright tests, page objects, utilities, configuration, reporting, GitHub repository, CI pipeline and a professional README). Submit your public GitHub repository URL for self-review against the model solution. This is your graduation submission.', 'url', 'automation-portfolio-project-workbook')
) as v(module_number, title, instructions, submission_type, template_slug)
where c.slug = 'practical-test-automation-playwright'
  and m.module_number = v.module_number
  and not exists (select 1 from public.assignments a where a.module_id = m.id);

-- ████████████████████████████████████████████████████████████
-- ▶ enrol-test-user.sql
-- ████████████████████████████████████████████████████████████

-- ============================================================
-- Enrol a test user into ALL courses.
-- Run in the Supabase SQL editor. Idempotent — re-running is safe and
-- will (re)activate every enrolment for the user.
-- ============================================================

insert into public.enrolments (user_id, course_id, status)
select u.id, c.id, 'active'
from auth.users u
cross join public.courses c
where u.email = 'doxley9@gmail.com'
on conflict (user_id, course_id) do update set status = 'active';

-- Confirm what the user is now enrolled in:
select c.title, e.status, e.enrolled_at
from public.enrolments e
join public.courses c on c.id = e.course_id
join auth.users u on u.id = e.user_id
where u.email = 'doxley9@gmail.com'
order by c.title;
